SELECT COUNT(DISTINCT S.PK_SIAPE) FROM CALC_HORA_AULA_MEDIA CHAM JOIN SERVIDOR S ON S.PK_SIAPE = CHAM.SIAPE WHERE CHAM.ANO = 2020 AND CHAM.SEMESTRE = 2 AND CHAM.SIGLA_CAMPUS = 'APA' AND S.SIGLA_CAMPUS = 'APA' AND LOWER(COALESCE(S.AREA_INGRESSO,'')) LIKE '%filosofia%' AND LOWER(COALESCE(S.CONTRATO,'')) = 'efetivos' AND S.SAIU_DO_IFG = FALSE